+	tests := []struct {
+		name string
+		want bool
+	}{
+		{"hq-mayor", true},
+		{"rig-witness", true},
+		{"rig-refinery", true},
+		{"rig-polecat-abc", true},
+		{"hq-deacon", true},
+		{"hq-boot", true},
+		{"rig-dog-fido", true},
+		{"my-personal-session", false},
+		{"", false},
+	}
+	for _, tt := range tests {
+		if got := isAgentSession(tt.name); got != tt.want {
+			t.Errorf("isAgentSession(%q) = %v, want %v", tt.name, got, tt.want)
+		}
+	}
+}
